"use client";

import { useState, useRef } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { triggerShake, getRandomComplete } from "@/lib/learningMessages";
import { getNextStep } from "@/content";

// ===== 类型 =====
type CompareAnswer = "same" | "different" | null;

interface FeatureRow {
  id: number;
  text: string;
  correct: "same" | "different";
}

interface QuizQuestion {
  question: string;
  options: string[];
  correctIndex: number;
}

// ===== 常量 =====
const FEATURES: FeatureRow[] = [
  { id: 0, text: "都有 4 条边", correct: "same" },
  { id: 1, text: "对边相等", correct: "same" },
  { id: 2, text: "四个角都是直角", correct: "same" },
  { id: 3, text: "四条边都相等", correct: "different" },
];

const QUIZZES: QuizQuestion[] = [
  {
    question: "长方形和正方形都有几条边？",
    options: ["A. 3 条", "B. 4 条", "C. 5 条", "D. 6 条"],
    correctIndex: 1,
  },
  {
    question: "正方形的四条边长度怎么样？",
    options: [
      "A. 都不同",
      "B. 对边相等",
      "C. 四条都相等",
      "D. 不知道",
    ],
    correctIndex: 2,
  },
  {
    question: "长方形有 4 个什么角？",
    options: ["A. 锐角", "B. 钝角", "C. 直角", "D. 平角"],
    correctIndex: 2,
  },
];

export default function ComparePage() {
  const [answers, setAnswers] = useState<CompareAnswer[]>(
    Array(FEATURES.length).fill(null)
  );
  const [tableDone, setTableDone] = useState(false);
  const [quizIndex, setQuizIndex] = useState(0);
  const [quizSolved, setQuizSolved] = useState<boolean[]>(
    Array(QUIZZES.length).fill(false)
  );
  const [completeMsg, setCompleteMsg] = useState("");

  const tableRef = useRef<HTMLDivElement>(null);
  const quizRefs = useRef<(HTMLDivElement | null)[]>([]);

  const allQuizDone = quizSolved.every(Boolean);

  const handleTableAnswer = (featureId: number, choice: "same" | "different") => {
    const feature = FEATURES[featureId];
    if (choice !== feature.correct) {
      triggerShake(tableRef.current);
      return;
    }

    setAnswers((prev) => {
      const next = [...prev];
      next[featureId] = choice;
      return next;
    });

    // 检查是否全部完成
    const newAnswers = [...answers];
    newAnswers[featureId] = choice;
    const allCorrect = FEATURES.every(
      (f, i) => newAnswers[i] === f.correct
    );
    if (allCorrect) {
      setTableDone(true);
    }
  };

  const handleQuizAnswer = (questionIndex: number, optionIndex: number) => {
    const question = QUIZZES[questionIndex];
    if (optionIndex !== question.correctIndex) {
      triggerShake(quizRefs.current[questionIndex]);
      return;
    }

    setQuizSolved((prev) => {
      const next = [...prev];
      next[questionIndex] = true;
      return next;
    });

    if (questionIndex === QUIZZES.length - 1) {
      setCompleteMsg(getRandomComplete());
    } else {
      setQuizIndex(questionIndex + 1);
    }
  };

  const nextStep = getNextStep("perimeter", "compare");

  return (
    <StepShell topicId="perimeter" stepId="compare">
      <div className="space-y-6">
        {/* SVG 对比区域 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
          <div className="flex items-center justify-center gap-8">
            {/* 长方形 */}
            <div className="flex flex-col items-center gap-2">
              <svg
                width={180}
                height={120}
                viewBox="0 0 180 120"
                className="rounded-xl"
                style={{ background: "var(--bg-soft)" }}
              >
                <rect
                  x={20}
                  y={20}
                  width={140}
                  height={80}
                  rx={8}
                  fill="var(--primary)"
                  fillOpacity={0.1}
                  stroke="var(--primary)"
                  strokeWidth={3}
                />
                {/* 长标注 */}
                <line
                  x1={20}
                  y1={108}
                  x2={160}
                  y2={108}
                  stroke="var(--text-secondary)"
                  strokeWidth={1}
                  markerStart="url(#arrowl)"
                  markerEnd="url(#arrowr)"
                />
                <text
                  x={90}
                  y={116}
                  textAnchor="middle"
                  fill="var(--text-secondary)"
                  fontSize={11}
                >
                  长 6cm
                </text>
                {/* 宽标注 */}
                <line
                  x1={8}
                  y1={20}
                  x2={8}
                  y2={100}
                  stroke="var(--text-secondary)"
                  strokeWidth={1}
                />
                <text
                  x={4}
                  y={64}
                  textAnchor="middle"
                  fill="var(--text-secondary)"
                  fontSize={11}
                  transform="rotate(-90 4 64)"
                >
                  宽 4cm
                </text>
                {/* 箭头定义 */}
                <defs>
                  <marker
                    id="arrowl"
                    markerWidth={6}
                    markerHeight={6}
                    refX={3}
                    refY={3}
                    orient="auto"
                  >
                    <path d="M6,0 L0,3 L6,6" fill="var(--text-secondary)" />
                  </marker>
                  <marker
                    id="arrowr"
                    markerWidth={6}
                    markerHeight={6}
                    refX={3}
                    refY={3}
                    orient="auto"
                  >
                    <path d="M0,0 L6,3 L0,6" fill="var(--text-secondary)" />
                  </marker>
                </defs>
              </svg>
              <span className="text-sm font-medium text-[var(--text)]">
                长方形
              </span>
            </div>

            {/* 正方形 */}
            <div className="flex flex-col items-center gap-2">
              <svg
                width={120}
                height={120}
                viewBox="0 0 120 120"
                className="rounded-xl"
                style={{ background: "var(--bg-soft)" }}
              >
                <rect
                  x={20}
                  y={20}
                  width={80}
                  height={80}
                  rx={8}
                  fill="var(--accent)"
                  fillOpacity={0.1}
                  stroke="var(--accent)"
                  strokeWidth={3}
                />
                <text
                  x={60}
                  y={116}
                  textAnchor="middle"
                  fill="var(--text-secondary)"
                  fontSize={11}
                >
                  边长 5cm
                </text>
              </svg>
              <span className="text-sm font-medium text-[var(--text)]">
                正方形
              </span>
            </div>
          </div>
        </div>

        {/* 对比表格 */}
        <div
          ref={tableRef}
          className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]"
        >
          <h2 className="mb-4 text-center text-lg font-bold text-[var(--text)]">
            比一比：长方形和正方形有什么相同和不同？
          </h2>
          <div className="space-y-3">
            {FEATURES.map((feature, i) => {
              const ans = answers[i];
              const isCorrect = ans === feature.correct;
              return (
                <div
                  key={feature.id}
                  className={`flex items-center justify-between rounded-xl border p-4 transition-all ${
                    isCorrect
                      ? "border-[var(--signal-success)] bg-[var(--signal-success)]/5"
                      : "border-[var(--border)] bg-[var(--bg-soft)]"
                  }`}
                >
                  <span className="text-[var(--text)]">{feature.text}</span>
                  <div className="flex gap-2">
                    {isCorrect ? (
                      <span className="rounded-full bg-[var(--signal-success)]/10 px-4 py-2 text-sm font-bold text-[var(--signal-success)]">
                        {ans === "same" ? "相同 ✓" : "不同 ✓"}
                      </span>
                    ) : (
                      <>
                        <button
                          onClick={() => handleTableAnswer(i, "same")}
                          className="rounded-full border border-[var(--border)] px-4 py-2 text-sm font-medium text-[var(--text-secondary)] transition-all hover:border-[var(--primary)] hover:bg-[var(--primary)]/10 hover:text-[var(--primary)]"
                        >
                          相同
                        </button>
                        <button
                          onClick={() => handleTableAnswer(i, "different")}
                          className="rounded-full border border-[var(--border)] px-4 py-2 text-sm font-medium text-[var(--text-secondary)] transition-all hover:border-[var(--accent)] hover:bg-[var(--accent)]/10 hover:text-[var(--accent)]"
                        >
                          不同
                        </button>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
          {tableDone && (
            <p className="mt-4 animate-float-in text-center text-sm font-medium text-[var(--signal-success)]">
              全部正确！你发现了吗：正方形是特殊的长方形。
            </p>
          )}
        </div>

        {/* 知识挑战 */}
        {tableDone && (
          <div className="space-y-4">
            <h2 className="text-center text-lg font-bold text-[var(--text)]">
              知识挑战
            </h2>
            {QUIZZES.map((q, qi) => {
              const isLocked = qi > 0 && !quizSolved[qi - 1];
              const isSolved = quizSolved[qi];
              return (
                <div
                  key={qi}
                  ref={(el) => { quizRefs.current[qi] = el; }}
                  className={`rounded-[var(--radius)] border p-6 shadow-[var(--shadow-sm)] transition-all ${
                    isSolved
                      ? "border-[var(--signal-success)] bg-[var(--signal-success)]/5"
                      : isLocked
                      ? "border-[var(--border)] bg-[var(--bg-soft)] opacity-50"
                      : "border-2 border-[var(--signal-focus)] bg-[var(--bg-card)]"
                  }`}
                >
                  <p className="mb-3 font-medium text-[var(--text)]">
                    {qi + 1}. {q.question}
                  </p>
                  <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
                    {q.options.map((opt, oi) => (
                      <button
                        key={oi}
                        disabled={isLocked || isSolved}
                        onClick={() => handleQuizAnswer(qi, oi)}
                        className={`rounded-lg border px-4 py-3 text-sm font-medium transition-all ${
                          isSolved && oi === q.correctIndex
                            ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10 text-[var(--signal-success)]"
                            : isSolved
                            ? "border-[var(--border)] bg-[var(--bg-soft)] text-[var(--text-muted)]"
                            : "border-[var(--border)] bg-[var(--bg-soft)] text-[var(--text)] hover:border-[var(--primary)] hover:bg-[var(--primary)]/10"
                        }`}
                      >
                        {opt}
                      </button>
                    ))}
                  </div>
                  {isSolved && (
                    <p className="mt-3 text-center text-sm font-bold text-[var(--signal-success)]">
                      回答正确！
                    </p>
                  )}
                </div>
              );
            })}
          </div>
        )}

        {/* 完成卡片 */}
        {allQuizDone && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--accent2)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <div className="text-4xl">🎉</div>
            <h3 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              长方形和正方形都有 4 条边、4 个直角，对边都相等。
              <br />
              正方形的特殊之处是：四条边都相等！
            </p>
            <div className="mt-5 flex justify-center gap-3">
              <button
                onClick={() => {
                  setAnswers(Array(FEATURES.length).fill(null));
                  setTableDone(false);
                  setQuizIndex(0);
                  setQuizSolved(Array(QUIZZES.length).fill(false));
                  setCompleteMsg("");
                }}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2.5 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再玩一次
              </button>
              {nextStep && (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--accent)] px-6 py-2.5 text-sm font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  下一步：{nextStep.label} →
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
