"use client";

import BackButton from "./BackButton";
import Link from "next/link";
import { getTopicSteps, getPrevStep } from "@/content";
import { playStep } from "@/lib/sounds";

interface StepShellProps {
  /** 知识点 ID，默认 'area' 兼容旧版 */
  topicId?: string;
  stepId: string;
  children: React.ReactNode;
}

/** 每步的彩色映射 */
const STEP_BAR_COLORS: string[] = [
  "var(--accent)",    // 1 珊瑚粉
  "var(--primary)",   // 2 天蓝
  "var(--accent2)",   // 3 薄荷绿
  "var(--accent3)",   // 4 阳光黄
  "var(--accent)",    // 5 珊瑚粉
  "var(--primary)",   // 6 天蓝
  "var(--accent2)",   // 7 薄荷绿
];

/** 步骤页面通用外壳：返回按钮 + 标题 + 步骤进度条 */
export default function StepShell({ topicId = "area", stepId, children }: StepShellProps) {
  const steps = getTopicSteps(topicId);
  const step = steps.find((s) => s.id === stepId);
  if (!step) return null;

  const prevStep = getPrevStep(topicId, stepId);
  const currentColor = STEP_BAR_COLORS[step.index - 1] || "var(--primary)";

  return (
    <main className="relative mx-auto w-full max-w-3xl px-6 py-8 pb-24">
      {/* 装饰性背景 */}
      <div
        className="pointer-events-none absolute -top-10 -right-10 h-36 w-36 rounded-full blur-3xl"
        style={{ backgroundColor: currentColor, opacity: 0.1 }}
      />

      <div className="relative z-10 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <BackButton href={`/learn/${topicId}`} />
          {prevStep && (
            <Link
              href={prevStep.path}
              onClick={() => playStep()}
              className="flex items-center gap-1 rounded-full px-3 py-1.5 text-sm font-medium text-[var(--text-secondary)] border border-[var(--border)] hover:bg-[var(--bg-card)] transition-all"
            >
              ← 上一步
            </Link>
          )}
        </div>
        <span
          className="rounded-full px-3 py-1 text-sm font-bold text-white"
          style={{ backgroundColor: currentColor }}
        >
          第 {step.index} / {steps.length} 步
        </span>
      </div>

      {/* 步骤进度条 */}
      <div className="mt-4 flex gap-1.5">
        {steps.map((s) => {
          const color = STEP_BAR_COLORS[s.index - 1] || "var(--primary)";
          const isActive = s.index === step.index;
          const isDone = s.index < step.index;
          return (
            <div
              key={s.id}
              className="h-2.5 flex-1 rounded-full transition-all duration-300"
              style={{
                backgroundColor: isDone
                  ? color
                  : isActive
                  ? color
                  : "var(--border)",
                opacity: isDone ? 0.6 : isActive ? 1 : 0.5,
                transform: isActive ? "scaleY(1.3)" : "scaleY(1)",
              }}
            />
          );
        })}
      </div>

      <div className="relative z-10 mt-6">
        <div className="flex items-center gap-3">
          <div
            className="flex h-14 w-14 items-center justify-center rounded-2xl text-3xl shadow-[var(--shadow-sm)]"
            style={{ backgroundColor: currentColor, color: "white" }}
          >
            {step.icon}
          </div>
          <div>
            <h1 className="text-2xl font-extrabold text-[var(--text)]">{step.label}</h1>
            <p className="text-sm text-[var(--text-secondary)]">{step.subtitle}</p>
          </div>
        </div>
      </div>

      <div className="relative z-10 mt-8">{children}</div>
    </main>
  );
}
